from flask import Flask, request, redirect
from flask_mail import Mail, Message
from flask_sqlalchemy import SQLAlchemy
import os
from itsdangerous import URLSafeTimedSerializer

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'your-database-uri'
app.config['SECRET_KEY'] = "secret-key"
app.config['SECURITY_PASSWORD_SALT'] = "security-password-salt"
app.config['MAIL_SERVER']='your-mail-server'
app.config['MAIL_PORT'] = 465
app.config['MAIL_USERNAME'] = 'your-email'
app.config['MAIL_PASSWORD'] = 'your-password'
app.config['MAIL_USE_TLS'] = False
app.config['MAIL_USE_SSL'] = True

db = SQLAlchemy(app)
mail = Mail(app)
s = URLSafeTimedSerializer("secret-key")

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(100), unique=True)
    password = db.Column(db.String(100))
    has_mfa = db.Column(db.Boolean, default=False)


@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    email = request.form['email']
    user = User.query.filter_by(email=email).first()
    
    if user:
        reset_token = s.dumps(email, salt='password-reset')
        reset_url = request.host_url + 'reset-token/' + reset_token

        msg = Message('Reset MFA', sender='noreply@tuts.com', recipients=[email])
        msg.body = 'Hello, we received a request to reset your MFA. Please go to the following link {}'.format(reset_url)
        
        mail.send(msg)
        return 'Check your email for instructions to reset your multi-factor authentication.' 

    return 'That email does not exist in our database, please try again.'

@app.route('/reset-token/<token>', methods=['GET'])
def handle_reset_token(token):
    email = s.loads(token, salt='password-reset', max_age=600)
    user = User.query.filter_by(email=email).first()

    if user:
        user.has_mfa = False
        db.session.commit()
        return redirect('login') 

    return 'Invalid token or token expired, please try again.'